
(()=>{
  const $=s=>document.querySelector(s), $$=s=>Array.from(document.querySelectorAll(s));
  const pipeline=['TARGET','EMIT','FILTER','ATLAS','TEST-PLAN','EVAL','INSERT','PROMOTE'];
  const presets={
    proofsite:{mission:'Improve the public proof institution without adding user-data collection or wallet behavior.', artifact:'navigation polish + evidence-status chip', risk:'LOW'},
    lean:{mission:'Package a Lean/Lake theorem-proving attempt as a replayable evidence docket.', artifact:'lake build log + no-sorry report', risk:'MEDIUM'},
    cyberdefense:{mission:'Harden a repo-owned defensive evidence hub while preserving no-external-scan boundaries.', artifact:'safe PR proposal + safety ledger', risk:'MEDIUM'},
    science:{mission:'Construct a falsification ladder for a scientific workflow claim.', artifact:'baseline comparison + probe schedule', risk:'MEDIUM'},
    market:{mission:'Simulate a MandateEpoch invention receipt without moving funds.', artifact:'epoch roots + simulated settlement receipt', risk:'LOW'}
  };
  const state={cycle:0,idx:0,shocks:0,candidates:0,baselines:0,dossier:0,novelty:42,advantage:46,evidence:28,replay:82,risk:22,persistence:36,crashed:false};
  function gate(name){const el=$(`[data-slider="${name}"]`);return el?Number(el.value):state[name]||0}
  function eci(){const e=gate('evidence'); if(e>=88) return 'E5'; if(e>=74) return 'E4'; if(e>=58) return 'E3'; if(e>=42) return 'E2'; if(e>=24) return 'E1'; return 'E0'}
  function authority(){const passed=gate('risk')<55 && gate('evidence')>=42 && state.baselines>0 && gate('persistence')>=55 && gate('replay')>=70; return passed?'PROMOTE':'DENY'}
  function updateFiles(){const p=presets[$('[data-preset]').value]||presets.proofsite; const E=eci(); $('[data-file="contract"]').textContent=JSON.stringify({mission:p.mission,risk:p.risk,authority:'human review required',done:'dossier + replay + claim boundary'},null,2); $('[data-file="state"]').textContent=`cycle_index: ${state.cycle}\ncurrent_stage: ${pipeline[state.idx]}\nreplay_integrity: ${gate('replay')}\ndrift_sentinel: ${state.crashed?'restart-required':'armed'}`; $('[data-file="eci"]').textContent=`${E} · executed evidence slider=${gate('evidence')}\nconfidence cannot inflate without execution\nartifact=${p.artifact}`; $('[data-file="dossier"]').textContent=gate('novelty')>=80?`Move-37 candidate detected.\nRequired: reproduce → stress → persist → dossier.\nDossier pages: ${state.dossier}`:`No Move-37 claim. Novelty below high-skepticism threshold.`; }
  function updateGates(){const vals={risk:100-gate('risk'),evidence:gate('evidence'),baseline:state.baselines?75:35,persistence:gate('persistence'),replay:gate('replay')}; const labels={risk:gate('risk')<55?'ALLOW':'RESTRICT',evidence:eci(),baseline:state.baselines?'COMPARED':'PENDING',persistence:gate('persistence')>=55?'PASS':'PROBE',replay:gate('replay')>=70?'READY':'DRIFT'}; for(const k of Object.keys(vals)){const row=$(`[data-gate-row="${k}"]`); if(row){row.querySelector('b').textContent=labels[k]; row.querySelector('meter').value=vals[k];}}
  }
  function render(msg){$$('[data-pipeline] button').forEach((b,i)=>b.classList.toggle('active',i===state.idx)); $('[data-metric="cycle"]').textContent=state.cycle; $('[data-metric="eci"]').textContent=eci(); $('[data-metric="novelty"]').textContent=(gate('novelty')/100).toFixed(2); $('[data-metric="authority"]').textContent=authority(); $('[data-ledger="candidates"]').textContent=state.candidates; $('[data-ledger="baselines"]').textContent=state.baselines; $('[data-ledger="shocks"]').textContent=state.shocks; $('[data-ledger="dossier"]').textContent=state.dossier; const high=gate('novelty')>=80; $('[data-breakthrough]').textContent=high?'Move-37 dossier required.':'Probe first.'; $('[data-breakthrough-note]').textContent=high?'High novelty raised the burden: reproduction, policy-shock stress tests, persistence, and dossier packaging are mandatory before any promotion.':'High novelty does not lower the burden of proof. It raises it: reproduce, stress-test, persist, then package a dossier.'; updateGates(); updateFiles(); const verdict=authority()==='PROMOTE'?'PROMOTION CANDIDATE · dossier ready':'PROBE / DENY · evidence gates incomplete'; $('[data-verdict]').textContent=verdict; $('[data-state]').textContent=msg||`Stage ${pipeline[state.idx]}: ${stageText(pipeline[state.idx])}`; }
  function stageText(s){return {TARGET:'Allocate exploration pressure across archive cells and mandates.',EMIT:'Generate candidate cards under explicit constraints.',FILTER:'Risk and interestingness filter route to reject/probe/refine/escalate.',ATLAS:'Extract causal triples, mechanism chains, and side effects.', 'TEST-PLAN':'Build falsification ladders and cheapest valid probes.',EVAL:'Run baseline-comparative evaluations and mint evidence objects.',INSERT:'Append accepted artifacts into archive cells only after gates.',PROMOTE:'Package dossier and queue human-review-ready promotion.'}[s]||s}
  function trace(t){const list=$('[data-trace]'); const li=document.createElement('li'); li.textContent=t; list.prepend(li); while(list.children.length>8) list.removeChild(list.lastChild)}
  function step(){ if(state.crashed){render('Runner halted. Restart from manifest before continuing.'); return; } state.idx=(state.idx+1)%pipeline.length; if(state.idx===0) state.cycle++; if(['EMIT','FILTER'].includes(pipeline[state.idx])) state.candidates++; if(pipeline[state.idx]==='EVAL') state.baselines++; if(pipeline[state.idx]==='PROMOTE' && gate('novelty')>=80 && gate('persistence')>=55) state.dossier++; trace(`${pipeline[state.idx]} · ${stageText(pipeline[state.idx])}`); render(); }
  function run(){for(let i=0;i<8;i++) step(); render('Cycle complete. Outcome authority remains mechanical: risk, evidence, baseline, persistence, replay, validator.');}
  function dossier(){const p=presets[$('[data-preset]').value]||presets.proofsite; return {type:'GoalOS.RSIDossier',release:'v50-loop-to-rsi',generatedAt:new Date().toISOString(),publicSafe:true,mission:p.mission,pipeline,cycleIndex:state.cycle,eci:eci(),noveltyDistance:gate('novelty')/100,advantageDelta:gate('advantage')/100,riskPressure:gate('risk')/100,replayIntegrity:gate('replay')/100,persistence:gate('persistence')/100,outcomeAuthority:authority(),move37:gate('novelty')>=80,counts:{candidates:state.candidates,baselines:state.baselines,shockTests:state.shocks,dossierPages:state.dossier},boundaries:{noWallet:true,noNetwork:true,noBrowserStorage:true,noUserDataWanted:true,noProductionAuthority:true},rules:['search control is not outcome authority','high novelty raises skepticism','no Move-37 claim without dossier','no ProofBundle, no settlement','no replay, no settlement','no authority, no autonomy']};}
  function download(){const blob=new Blob([JSON.stringify(dossier(),null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='goalos-rsi-dossier-v50.json'; document.body.appendChild(a); a.click(); URL.revokeObjectURL(a.href); a.remove();}
  function copyBrief(){const d=dossier(); const text=`GoalOS RSI demo: ${d.mission}\nECI: ${d.eci}; novelty: ${d.noveltyDistance}; authority: ${d.outcomeAuthority}.\nBoundary: public-safe browser-local demonstration only; no wallet, no network, no production authority.`; if(navigator.clipboard&&navigator.clipboard.writeText) navigator.clipboard.writeText(text); trace('Review brief prepared locally.');}
  document.addEventListener('click',e=>{const a=e.target.closest('[data-action]'); if(!a) return; const k=a.dataset.action; if(k==='run') run(); if(k==='novelty'){ $('[data-slider="novelty"]').value=86; $('[data-slider="evidence"]').value=44; trace('High novelty injected: skepticism increased, probe-first required.'); render('High novelty detected. The system refuses narrative promotion and demands reproduction, stress, persistence, and dossier.'); } if(k==='shock'){state.shocks++; $('[data-slider="persistence"]').value=Math.min(100,gate('persistence')+18); trace('Policy-shock stress test recorded.'); render('Shock test complete. Persistence gate updated.');} if(k==='restart'){state.crashed=false; trace('Runner restarted from manifest without silent state reset.'); render('Restart from manifest succeeded. Cycle index and state hashes preserved.');} if(k==='export') download(); if(k==='copy') copyBrief(); });
  $$('input[type="range"],[data-preset]').forEach(x=>x.addEventListener('input',()=>render('Controls updated. Outcome authority recalculated.')));
  render('Ready. Run one RSI cycle or inject high novelty to see Move-37 handling.');
})();
